export const login = async (emailOrPhone, password) => {
    try {
        const response = await API.post('/auth/login', {
            email_or_phone: emailOrPhone,
            password
        });
        return response.data;
    } catch (error) {
        console.error('Login error:', error);
        throw error;
    }
};
